import{L as l,a as d}from"./LandingFooter-BPy1eYwB.js";import{_ as c}from"./index-yDPpn0m2.js";import{n as o,l as i,a as r,s as a,E as n,F as f,H as u,t as v}from"./vendor-BEMLayfT.js";import"./PayLogo-CN5y9Sq_.js";const p={class:"page-wrapper"},h={class:"legal-section"},y={class:"container"},g={class:"legal-layout"},m={class:"toc-nav"},w=["href"],b={__name:"PrivacyPolicyView",setup(k){const s=[{id:"information-we-collect",title:"1. Information We Collect"},{id:"how-we-use-information",title:"2. How We Use Your Information"},{id:"data-sharing",title:"3. Data Sharing and Disclosure"},{id:"data-security",title:"4. Data Security"},{id:"data-retention",title:"5. Data Retention"},{id:"your-rights",title:"6. Your Rights"},{id:"cookies",title:"7. Cookies and Tracking"},{id:"children",title:"8. Children's Privacy"},{id:"changes",title:"9. Changes to This Policy"},{id:"contact",title:"10. Contact Us"}];return(P,e)=>(i(),o("div",p,[r(l),a("main",null,[e[2]||(e[2]=n('<section class="page-hero" data-v-16ff8e6a><div class="container" data-v-16ff8e6a><div class="hero-badge" data-v-16ff8e6a><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" width="16" height="16" data-v-16ff8e6a><path stroke-linecap="round" stroke-linejoin="round" d="M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.749c0 5.592 3.824 10.29 9 11.623 5.176-1.332 9-6.03 9-11.622 0-1.31-.21-2.571-.598-3.751h-.152c-3.196 0-6.1-1.248-8.25-3.285Z" data-v-16ff8e6a></path></svg> Last Updated: March 1, 2026 </div><h1 class="page-title" data-v-16ff8e6a>Privacy Policy</h1><p class="page-subtitle" data-v-16ff8e6a>We take your privacy seriously. This policy explains what data we collect, how we use it, and your rights as a user of Archangel Payroll.</p></div></section>',1)),a("section",h,[a("div",y,[a("div",g,[a("nav",m,[e[0]||(e[0]=a("div",{class:"toc-title"},"Contents",-1)),a("ul",null,[(i(),o(f,null,u(s,t=>a("li",{key:t.id},[a("a",{href:`#${t.id}`,class:"toc-link"},v(t.title),9,w)])),64))])]),e[1]||(e[1]=n('<article class="legal-content" data-v-16ff8e6a><div class="intro-callout" data-v-16ff8e6a><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" width="20" height="20" data-v-16ff8e6a><path stroke-linecap="round" stroke-linejoin="round" d="m11.25 11.25.041-.02a.75.75 0 0 1 1.063.852l-.708 2.836a.75.75 0 0 0 1.063.853l.041-.021M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Zm-9-3.75h.008v.008H12V8.25Z" data-v-16ff8e6a></path></svg><p data-v-16ff8e6a>This Privacy Policy applies to Archangel Technologies Inc. (&quot;Archangel Payroll,&quot; &quot;we,&quot; &quot;us,&quot; or &quot;our&quot;) and governs data collection and usage for our payroll platform and related services.</p></div><section id="information-we-collect" data-v-16ff8e6a><h2 data-v-16ff8e6a>1. Information We Collect</h2><p data-v-16ff8e6a>We collect information you provide directly to us, information generated by your use of the service, and information from third parties.</p><h3 data-v-16ff8e6a>Account Information</h3><p data-v-16ff8e6a>When you create an account, we collect your name, email address, company name, phone number, and billing information.</p><h3 data-v-16ff8e6a>Employee Data</h3><p data-v-16ff8e6a>As a payroll processor, we collect and process employee data on your behalf, including: full legal names, Social Security Numbers (SSNs) or Tax IDs, addresses, dates of birth, bank account information for direct deposit, compensation and benefits data, and employment status information.</p><h3 data-v-16ff8e6a>Usage Data</h3><p data-v-16ff8e6a>We automatically collect information about how you access and use the platform, including IP addresses, browser type, pages visited, time spent, and actions taken.</p></section><section id="how-we-use-information" data-v-16ff8e6a><h2 data-v-16ff8e6a>2. How We Use Your Information</h2><p data-v-16ff8e6a>We use the information we collect to:</p><ul data-v-16ff8e6a><li data-v-16ff8e6a>Provide, operate, and improve the Archangel Payroll platform</li><li data-v-16ff8e6a>Process payroll, tax filings, and related transactions on your behalf</li><li data-v-16ff8e6a>Communicate with you about your account, updates, and support issues</li><li data-v-16ff8e6a>Comply with legal obligations including tax reporting requirements</li><li data-v-16ff8e6a>Detect and prevent fraud, security incidents, and abuse</li><li data-v-16ff8e6a>Analyze usage trends to improve the platform</li></ul><p data-v-16ff8e6a>We do not sell your personal information or your employees&#39; data to third parties.</p></section><section id="data-sharing" data-v-16ff8e6a><h2 data-v-16ff8e6a>3. Data Sharing and Disclosure</h2><p data-v-16ff8e6a>We may share information in the following circumstances:</p><h3 data-v-16ff8e6a>Service Providers</h3><p data-v-16ff8e6a>We work with third-party vendors who assist us in providing the service (e.g., cloud hosting, payment processors, tax filing agencies). These providers are contractually obligated to protect your data.</p><h3 data-v-16ff8e6a>Legal Requirements</h3><p data-v-16ff8e6a>We may disclose information to government authorities (such as tax agencies) as required by law, or to comply with legal process.</p><h3 data-v-16ff8e6a>Business Transfers</h3><p data-v-16ff8e6a>In the event of a merger, acquisition, or sale of assets, your data may be transferred. We will notify you before your data is transferred and becomes subject to a different privacy policy.</p></section><section id="data-security" data-v-16ff8e6a><h2 data-v-16ff8e6a>4. Data Security</h2><p data-v-16ff8e6a>We implement industry-standard security measures to protect your data, including:</p><ul data-v-16ff8e6a><li data-v-16ff8e6a>AES-256 encryption for data at rest</li><li data-v-16ff8e6a>TLS 1.3 for all data in transit</li><li data-v-16ff8e6a>SOC 2 Type II certified infrastructure</li><li data-v-16ff8e6a>Role-based access controls and multi-factor authentication</li><li data-v-16ff8e6a>Regular penetration testing and security audits</li></ul><p data-v-16ff8e6a>No method of transmission over the Internet or electronic storage is 100% secure. We strive to use commercially acceptable means to protect your data but cannot guarantee absolute security.</p></section><section id="data-retention" data-v-16ff8e6a><h2 data-v-16ff8e6a>5. Data Retention</h2><p data-v-16ff8e6a>We retain your data for as long as your account is active or as needed to provide services. We will retain and use your information as necessary to comply with legal obligations (payroll records are generally required to be retained for 3–7 years), resolve disputes, and enforce our agreements.</p><p data-v-16ff8e6a>Upon account termination, we will delete or anonymize your personal data within 90 days, except where retention is required by law.</p></section><section id="your-rights" data-v-16ff8e6a><h2 data-v-16ff8e6a>6. Your Rights</h2><p data-v-16ff8e6a>Depending on your location, you may have the following rights regarding your personal data:</p><ul data-v-16ff8e6a><li data-v-16ff8e6a><strong data-v-16ff8e6a>Access:</strong> Request a copy of the personal data we hold about you.</li><li data-v-16ff8e6a><strong data-v-16ff8e6a>Correction:</strong> Request that we correct inaccurate or incomplete data.</li><li data-v-16ff8e6a><strong data-v-16ff8e6a>Deletion:</strong> Request deletion of your personal data, subject to legal retention requirements.</li><li data-v-16ff8e6a><strong data-v-16ff8e6a>Portability:</strong> Receive your data in a structured, machine-readable format.</li><li data-v-16ff8e6a><strong data-v-16ff8e6a>Objection:</strong> Object to certain types of processing of your data.</li></ul><p data-v-16ff8e6a>To exercise your rights, contact us at <a href="mailto:privacy@archangelpayroll.com" data-v-16ff8e6a>privacy@archangelpayroll.com</a>.</p></section><section id="cookies" data-v-16ff8e6a><h2 data-v-16ff8e6a>7. Cookies and Tracking</h2><p data-v-16ff8e6a>We use cookies and similar tracking technologies to operate and improve our service. We use session cookies (which expire when you close your browser) and persistent cookies (which remain until deleted).</p><p data-v-16ff8e6a>You can control cookies through your browser settings. Disabling cookies may affect your ability to use certain features of the platform.</p></section><section id="children" data-v-16ff8e6a><h2 data-v-16ff8e6a>8. Children&#39;s Privacy</h2><p data-v-16ff8e6a>Archangel Payroll is not intended for use by individuals under 16 years of age. We do not knowingly collect personal information from children. If you believe we have inadvertently collected such information, please contact us immediately.</p></section><section id="changes" data-v-16ff8e6a><h2 data-v-16ff8e6a>9. Changes to This Policy</h2><p data-v-16ff8e6a>We may update this Privacy Policy from time to time. We will notify you of material changes by posting the new policy on this page and updating the &quot;Last Updated&quot; date. We encourage you to review this policy periodically.</p></section><section id="contact" data-v-16ff8e6a><h2 data-v-16ff8e6a>10. Contact Us</h2><p data-v-16ff8e6a>If you have questions about this Privacy Policy or our data practices, please contact:</p><div class="contact-block" data-v-16ff8e6a><div data-v-16ff8e6a><strong data-v-16ff8e6a>Archangel Technologies Inc.</strong></div><div data-v-16ff8e6a>Attn: Privacy Team</div><div data-v-16ff8e6a>Email: <a href="mailto:privacy@archangelpayroll.com" data-v-16ff8e6a>privacy@archangelpayroll.com</a></div></div></section></article>',1))])])])]),r(d)]))}},x=c(b,[["__scopeId","data-v-16ff8e6a"]]);export{x as default};
